mapper.update:
UPDATE students
SET sname = #{sname}, sgender = #{sgender}, smajor = #{smajor}, sbirthday = #{sbirthday}, scredit_points = #{screditPoints}
WHERE sid = #{sid}

mapper.select:
SELECT sid, sname, sgender, smajor, sbirthday, scredit_points
FROM students


    AND sname LIKE CONCAT('%', #{name}, '%')


    AND smajor = #{major}


    AND scredit_points >= #{minCredits}


    AND scredit_points <= #{maxCredits}



  LIMIT #{limit} OFFSET #{offset}
